import requests
import json
import sys
import time
from typing import Optional


class KongAdminClient:
    """Client for interacting with Kong's Admin API."""

    def __init__(self, admin_url: str = "http://localhost:8001", timeout: int = 30):
        self.admin_url = admin_url.rstrip("/")
        self.timeout = timeout
        self.session = requests.Session()
        self.session.headers.update({
            "Content-Type": "application/json",
            "Accept": "application/json",
        })

    def _request(self, method: str, endpoint: str, data: Optional[dict] = None) -> dict:
        """Make a request to the Kong Admin API."""
        url = f"{self.admin_url}{endpoint}"
        try:
            response = self.session.request(
                method=method,
                url=url,
                json=data,
                timeout=self.timeout,
            )
            if response.status_code in (200, 201):
                return {"success": True, "data": response.json(), "status_code": response.status_code}
            elif response.status_code == 409:
                return {"success": False, "error": "Already exists (conflict)", "status_code": 409,
                        "data": response.json() if response.text else {}}
            elif response.status_code == 204:
                return {"success": True, "data": {}, "status_code": 204}
            else:
                return {
                    "success": False,
                    "error": response.text,
                    "status_code": response.status_code,
                    "data": response.json() if response.text else {},
                }
        except requests.exceptions.ConnectionError as e:
            return {"success": False, "error": f"Connection error: {e}", "status_code": 0}
        except requests.exceptions.Timeout as e:
            return {"success": False, "error": f"Timeout: {e}", "status_code": 0}
        except Exception as e:
            return {"success": False, "error": f"Unexpected error: {e}", "status_code": 0}

    def get(self, endpoint: str) -> dict:
        return self._request("GET", endpoint)

    def post(self, endpoint: str, data: dict) -> dict:
        return self._request("POST", endpoint, data)

    def put(self, endpoint: str, data: dict) -> dict:
        return self._request("PUT", endpoint, data)

    def patch(self, endpoint: str, data: dict) -> dict:
        return self._request("PATCH", endpoint, data)

    def delete(self, endpoint: str) -> dict:
        return self._request("DELETE", endpoint)

    # --- Health Check ---

    def check_health(self) -> bool:
        """Check if Kong Admin API is reachable."""
        result = self.get("/status")
        return result["success"]

    def wait_for_kong(self, max_retries: int = 30, delay: int = 2) -> bool:
        """Wait for Kong to become available."""
        print("Waiting for Kong Admin API to become available...")
        for attempt in range(1, max_retries + 1):
            if self.check_health():
                print(f"  Kong is ready (attempt {attempt})")
                return True
            print(f"  Attempt {attempt}/{max_retries} - Kong not ready, retrying in {delay}s...")
            time.sleep(delay)
        print("  Kong Admin API is not available after maximum retries.")
        return False

    def get_info(self) -> dict:
        """Get Kong node information."""
        return self.get("/")

    # --- Upstreams ---

    def create_upstream(self, name: str, **kwargs) -> dict:
        """
        Create an upstream.

        Args:
            name: The upstream name (usually matches the service host).
            **kwargs: Additional upstream settings like algorithm, hash_on, etc.
        """
        data = {"name": name}
        data.update(kwargs)
        print(f"Creating upstream: {name}")
        result = self.post("/upstreams", data)
        self._log_result("Upstream", name, result)
        return result

    def get_upstream(self, name_or_id: str) -> dict:
        return self.get(f"/upstreams/{name_or_id}")

    def list_upstreams(self) -> dict:
        return self.get("/upstreams")

    def delete_upstream(self, name_or_id: str) -> dict:
        print(f"Deleting upstream: {name_or_id}")
        return self.delete(f"/upstreams/{name_or_id}")

    def update_upstream(self, name_or_id: str, **kwargs) -> dict:
        return self.patch(f"/upstreams/{name_or_id}", kwargs)

    # --- Targets ---

    def add_target(self, upstream_name_or_id: str, target: str, weight: int = 100, **kwargs) -> dict:
        """
        Add a target to an upstream.

        Args:
            upstream_name_or_id: The upstream name or ID.
            target: Target address (ip:port or hostname:port).
            weight: Weight for load balancing (0-65535, default 100).
        """
        data = {"target": target, "weight": weight}
        data.update(kwargs)
        print(f"  Adding target: {target} (weight={weight}) to upstream: {upstream_name_or_id}")
        result = self.post(f"/upstreams/{upstream_name_or_id}/targets", data)
        self._log_result("Target", target, result)
        return result

    def list_targets(self, upstream_name_or_id: str) -> dict:
        return self.get(f"/upstreams/{upstream_name_or_id}/targets")

    def delete_target(self, upstream_name_or_id: str, target_or_id: str) -> dict:
        return self.delete(f"/upstreams/{upstream_name_or_id}/targets/{target_or_id}")

    def set_target_healthy(self, upstream_name_or_id: str, target_or_id: str) -> dict:
        return self.put(f"/upstreams/{upstream_name_or_id}/targets/{target_or_id}/healthy", {})

    def set_target_unhealthy(self, upstream_name_or_id: str, target_or_id: str) -> dict:
        return self.put(f"/upstreams/{upstream_name_or_id}/targets/{target_or_id}/unhealthy", {})

    # --- Services ---

    def create_service(self, name: str, **kwargs) -> dict:
        """
        Create a service.

        Args:
            name: The service name.
            **kwargs: Service configuration (url, host, port, protocol, path, retries,
                      connect_timeout, write_timeout, read_timeout, etc.)
        """
        data = {"name": name}
        data.update(kwargs)
        print(f"Creating service: {name}")
        result = self.post("/services", data)
        self._log_result("Service", name, result)
        return result

    def get_service(self, name_or_id: str) -> dict:
        return self.get(f"/services/{name_or_id}")

    def list_services(self) -> dict:
        return self.get("/services")

    def delete_service(self, name_or_id: str) -> dict:
        print(f"Deleting service: {name_or_id}")
        return self.delete(f"/services/{name_or_id}")

    def update_service(self, name_or_id: str, **kwargs) -> dict:
        return self.patch(f"/services/{name_or_id}", kwargs)

    # --- Routes ---

    def create_route(self, service_name_or_id: str, **kwargs) -> dict:
        """
        Create a route for a service.

        Args:
            service_name_or_id: The service name or ID to attach the route to.
            **kwargs: Route configuration (name, paths, hosts, methods, protocols,
                      strip_path, preserve_host, headers, etc.)
        """
        data = {"service": {"name": service_name_or_id} if not self._is_uuid(service_name_or_id)
                else {"id": service_name_or_id}}
        data.update(kwargs)
        route_name = kwargs.get("name", "unnamed")
        print(f"  Creating route: {route_name} for service: {service_name_or_id}")
        result = self.post("/routes", data)
        self._log_result("Route", route_name, result)
        return result

    def get_route(self, name_or_id: str) -> dict:
        return self.get(f"/routes/{name_or_id}")

    def list_routes(self, service_name_or_id: Optional[str] = None) -> dict:
        if service_name_or_id:
            return self.get(f"/services/{service_name_or_id}/routes")
        return self.get("/routes")

    def delete_route(self, name_or_id: str) -> dict:
        print(f"  Deleting route: {name_or_id}")
        return self.delete(f"/routes/{name_or_id}")

    def update_route(self, name_or_id: str, **kwargs) -> dict:
        return self.patch(f"/routes/{name_or_id}", kwargs)

    # --- Plugins ---

    def add_plugin(self, name: str, config: Optional[dict] = None,
                   service_name_or_id: Optional[str] = None,
                   route_name_or_id: Optional[str] = None,
                   consumer_name_or_id: Optional[str] = None,
                   enabled: bool = True, **kwargs) -> dict:
        """
        Add a plugin globally, or scoped to a service/route/consumer.

        Args:
            name: Plugin name (e.g., 'rate-limiting', 'key-auth', 'cors').
            config: Plugin-specific configuration dict.
            service_name_or_id: Scope to a service.
            route_name_or_id: Scope to a route.
            consumer_name_or_id: Scope to a consumer.
            enabled: Whether the plugin is enabled.
        """
        data = {"name": name, "enabled": enabled}
        if config:
            data["config"] = config
        if service_name_or_id:
            data["service"] = ({"name": service_name_or_id}
                               if not self._is_uuid(service_name_or_id)
                               else {"id": service_name_or_id})
        if route_name_or_id:
            data["route"] = ({"name": route_name_or_id}
                             if not self._is_uuid(route_name_or_id)
                             else {"id": route_name_or_id})
        if consumer_name_or_id:
            data["consumer"] = ({"username": consumer_name_or_id}
                                if not self._is_uuid(consumer_name_or_id)
                                else {"id": consumer_name_or_id})
        data.update(kwargs)

        scope = "global"
        if service_name_or_id:
            scope = f"service:{service_name_or_id}"
        elif route_name_or_id:
            scope = f"route:{route_name_or_id}"

        print(f"  Adding plugin: {name} (scope: {scope})")
        result = self.post("/plugins", data)
        self._log_result("Plugin", name, result)
        return result

    def list_plugins(self) -> dict:
        return self.get("/plugins")

    def delete_plugin(self, plugin_id: str) -> dict:
        return self.delete(f"/plugins/{plugin_id}")

    def get_enabled_plugins(self) -> dict:
        return self.get("/plugins/enabled")

    # --- Consumers ---

    def create_consumer(self, username: str, custom_id: Optional[str] = None, **kwargs) -> dict:
        """Create a consumer."""
        data = {"username": username}
        if custom_id:
            data["custom_id"] = custom_id
        data.update(kwargs)
        print(f"Creating consumer: {username}")
        result = self.post("/consumers", data)
        self._log_result("Consumer", username, result)
        return result

    def get_consumer(self, username_or_id: str) -> dict:
        return self.get(f"/consumers/{username_or_id}")

