        data = {"cert": cert, "key": key}
        if snis:
            data["snis"] = snis
        data.update(kwargs)
        print(f"Creating certificate (SNIs: {snis})")
        result = self.post("/certificates", data)
        self._log_result("Certificate", str(snis), result)
        return result

