    # --- Utility Methods ---

    @staticmethod
    def _is_uuid(value: str) -> bool:
        """Check if a string looks like a UUID."""
        import re
        uuid_pattern = re.compile(
            r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$',
            re.IGNORECASE
        )
        return bool(uuid_pattern.match(value))

    @staticmethod
    def _log_result(resource_type: str, name: str, result: dict):
        """Log the result of an API operation."""
        if result["success"]:
            resource_id = result["data"].get("id", "N/A")
            print(f"    ✓ {resource_type} '{name}' created successfully (id: {resource_id})")
        elif result["status_code"] == 409:
            print(f"    ⚠ {resource_type} '{name}' already exists")
        else:
            print(f"    ✗ Failed to create {resource_type} '{name}': "
                  f"[{result['status_code']}] {result['error']}")

    # --- Declarative Configuration ---

    def apply_config(self, config: dict) -> dict:
        """
        Apply a full declarative configuration.
        This creates upstreams, targets, services, routes, plugins, and consumers
        from a structured configuration dictionary.
        """
        results = {
            "upstreams": [],
            "services": [],
            "routes": [],
            "plugins": [],
            "consumers": [],
        }

        # 1. Create upstreams and targets
        for upstream_config in config.get("upstreams", []):
            targets = upstream_config.pop("targets", [])
            healthchecks = upstream_config.pop("healthchecks", None)

            upstream_data = {**upstream_config}
            if healthchecks:
                upstream_data["healthchecks"] = healthchecks

            result = self.create_upstream(**upstream_data)
            results["upstreams"].append(result)

            if result["success"] or result["status_code"] == 409:
                upstream_name = upstream_config["name"]
                for target_config in targets:
                    t_result = self.add_target(upstream_name, **target_config)
                    results["upstreams"].append(t_result)

        # 2. Create services
        for service_config in config.get("services", []):
            routes = service_config.pop("routes", [])
            plugins = service_config.pop("plugins", [])

            result = self.create_service(**service_config)
            results["services"].append(result)

            service_name = service_config["name"]

            # 3. Create routes for service
            if result["success"] or result["status_code"] == 409:
                for route_config in routes:
                    route_plugins = route_config.pop("plugins", [])
                    r_result = self.create_route(service_name, **route_config)
                    results["routes"].append(r_result)

                    # Route-level plugins
                    if r_result["success"] or r_result["status_code"] == 409:
                        route_name = route_config.get("name")
                        for plugin_config in route_plugins:
                            p_result = self.add_plugin(
                                route_name_or_id=route_name,
                                **plugin_config,
                            )
                            results["plugins"].append(p_result)

                # Service-level plugins
                for plugin_config in plugins:
                    p_result = self.add_plugin(
                        service_name_or_id=service_name,
                        **plugin_config,
                    )
                    results["plugins"].append(p_result)

        # 4. Global plugins
        for plugin_config in config.get("plugins", []):
            result = self.add_plugin(**plugin_config)
            results["plugins"].append(result)

        # 5. Consumers
        for consumer_config in config.get("consumers", []):
            credentials = consumer_config.pop("credentials", {})
            acls = consumer_config.pop("acls", [])

            result = self.create_consumer(**consumer_config)
            results["consumers"].append(result)

            if result["success"] or result["status_code"] == 409:
                username = consumer_config["username"]

                # Key-auth credentials
                for key_config in credentials.get("key-auth", []):
                    self.create_consumer_key_auth(username, **key_config)

                # Basic-auth credentials
                for basic_config in credentials.get("basic-auth", []):
                    self.create_consumer_basic_auth(username, **basic_config)

                # JWT credentials
                for jwt_config in credentials.get("jwt", []):
                    self.create_consumer_jwt(username, **jwt_config)

                # ACLs
                for acl_group in acls:
                    print(f"  Adding ACL group '{acl_group}' to consumer: {username}")
                    self.post(f"/consumers/{username}/acls", {"group": acl_group})

        return results

    def cleanup_config(self, config: dict):
        """Remove all resources defined in a configuration (reverse order)."""
        print("\n" + "=" * 60)
        print("CLEANING UP CONFIGURATION")
        print("=" * 60)

        # Delete routes first
        for service_config in config.get("services", []):
            for route_config in service_config.get("routes", []):
                route_name = route_config.get("name")
                if route_name:
                    self.delete_route(route_name)

        # Delete services
        for service_config in config.get("services", []):
            self.delete_service(service_config["name"])

        # Delete upstreams
        for upstream_config in config.get("upstreams", []):
            self.delete_upstream(upstream_config["name"])

        # Delete consumers
        for consumer_config in config.get("consumers", []):
            self.delete_consumer(consumer_config["username"])


