def print_summary(kong: KongAdminClient):
    """Print a summary of current Kong configuration."""
    print("\n" + "=" * 60)
    print("KONG CONFIGURATION SUMMARY")
    print("=" * 60)

    # Node info
    info = kong.get_info()
    if info["success"]:
        data = info["data"]
        print(f"\nKong Version: {data.get('version', 'N/A')}")
        print(f"Node ID: {data.get('node_id', 'N/A')}")
        print(f"Hostname: {data.get('hostname', 'N/A')}")
        tagline = data.get("tagline", "")
        if tagline:
            print(f"Tagline: {tagline}")

    # Services
    services = kong.list_services()
    if services["success"]:
        service_list = services["data"].get("data", [])
        print(f"\nServices ({len(service_list)}):")
        for svc in service_list:
            print(f"  - {svc['name']}: {svc.get('protocol', 'http')}://"
                  f"{svc.get('host', 'N/A')}:{svc.get('port', 80)}{svc.get('path', '/')}")

            # Routes for each service
            routes = kong.list_routes(svc["id"])
            if routes["success"]:
                route_list = routes["data"].get("data", [])
                for route in route_list:
                    paths = route.get("paths", [])
                    methods = route.get("methods", ["ALL"])
                    print(f"      Route: {route.get('name', 'unnamed')} "
                          f"| Paths: {paths} | Methods: {methods}")

    # Upstreams
    upstreams = kong.list_upstreams()
    if upstreams["success"]:
        upstream_list = upstreams["data"].get("data", [])
        print(f"\nUpstreams ({len(upstream_list)}):")
        for ups in upstream_list:
            print(f"  - {ups['name']} (algorithm: {ups.get('algorithm', 'round-robin')})")
            targets = kong.list_targets(ups["id"])
            if targets["success"]:
                target_list = targets["data"].get("data", [])
                for t in target_list:
                    print(f"      Target: {t['target']} (weight: {t.get('weight', 100)})")

    # Consumers
    consumers = kong.list_consumers()
    if consumers["success"]:
        consumer_list = consumers["data"].get("data", [])
        print(f"\nConsumers ({len(consumer_list)}):")
        for c in consumer_list:
            print(f"  - {c.get('username', 'N/A')} (custom_id: {c.get('custom_id', 'N/A')})")

    # Plugins
    plugins = kong.list_plugins()
    if plugins["success"]:
        plugin_list = plugins["data"].get("data", [])
        print(f"\nPlugins ({len(plugin_list)}):")
        for p in plugin_list:
            scope = "global"
            if p.get("service"):
                scope = f"service:{p['service'].get('id', 'N/A')}"
            elif p.get("route"):
                scope = f"route:{p['route'].get('id', 'N/A')}"
            enabled = "✓" if p.get("enabled", True) else "✗"
            print(f"  - [{enabled}] {p['name']} (scope: {scope})")

    print("\n" + "=" * 60)


def main():
    """Main function to configure Kong API Gateway."""
    import argparse

    parser = argparse.ArgumentParser(description="Configure Kong API Gateway via Admin API")
    parser.add_argument(
        "--admin-url",
        default="http://localhost:8001",
        help="Kong Admin API URL (default: http://localhost:8001)",
    )
    parser.add_argument(
        "--config-file",
        help="Path to JSON configuration file (optional, uses built-in sample if not provided)",
    )
    parser.add_argument(
        "--action",
        choices=["apply", "cleanup", "summary", "apply-and-summary"],
        default="apply-and-summary",
        help="Action to perform (default: apply-and-summary)",
    )
    parser.add_argument(
        "--no-wait",
        action="store_true",
        help="Don't wait for Kong to become available",
    )

    args = parser.parse_args()

    # Initialize client
    kong = KongAdminClient(admin_url=args.admin_url)

    # Wait for Kong
    if not args.no_wait:
        if not kong.wait_for_kong():
            print("ERROR: Kong Admin API is not available. Exiting.")
            sys.exit(1)

    # Load configuration
    if args.config_file:
        print(f"Loading configuration from: {args.config_file}")
        with open(args.config_file, "r") as f:
            config = json.load(f)
    else:
        print("Using built-in sample configuration")
        config = get_sample_configuration()

    # Perform action
    if args.action == "apply":
        print("\n" + "=" * 60)
        print("APPLYING KONG CONFIGURATION")
        print("=" * 60)
        kong.apply_config(config)

    elif args.action == "cleanup":
        kong.cleanup_config(config)

    elif args.action == "summary":
        print_summary(kong)

    elif args.action == "apply-and-summary":
        print("\n" + "=" * 60)
        print("APPLYING KONG CONFIGURATION")
        print("=" * 60)
        kong.apply_config(config)
        print_summary(kong)

    print("\nDone!")


if __name__ == "__main__":
    main()